// // This module implements a 32-bit synchronous down counter that decrements its value on every positive edge of the clock and resets to zero when the reset signal is asserted. The counter should be disabled by an enable signal; if the enable signal is high, the counter should hold its value.
module counter_32bit (
    input clk,
    input rst,
    input en,
    output reg [31:0] count
);
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            count <= 32'b0;
        end else if (en) begin
            count <= count + 1;
        end
    end
endmodule
